// 二分答案法
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var check = [&](int mid)->bool {
		var vis = vector<int>(n + 1);
		fa(i, 1, m)vis[a[i]]++;
		fa(i, 0, mid)if (!vis[i])return 1;
		fa(i, m + 1, n) {
			vis[a[i]]++;
			vis[a[i - m]]--;
			if (a[i - m] <= mid and !vis[a[i - m]])return 1;
		}
		return 0;
		};
	int l = 0, r = n, ans = 0;
	while (l <= r) {
		int mid = l + r >> 1;
		if (check(mid)) {
			ans = mid;
			r = mid - 1;
		}
		else l = mid + 1;
	}
	cout << ans << endl;
	return;
}

// O(n) 间隙法
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var mp = vector<int>(n + 1);
	int ans = n;
	fa(i, 1, n) {
		if (i - mp[a[i]] > m)ans = min(ans, a[i]);
		mp[a[i]] = i;
	}
	fa(i, 0, n)
		if (!mp[i] or n + 1 - mp[i] > m)
			ans = min(ans, i);
	cout << ans << endl;
	return;
}
